// src/main/java/com/abcbank/repository/AccountRepository.java
package com.abcbank.repository;

import com.abcbank.model.Account;
import com.abcbank.model.AccountType;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;

@Repository
public interface AccountRepository extends JpaRepository<Account, Long> {

    Optional<Account> findByAccountNumber(String accountNumber);

    List<Account> findByUserId(Long userId);

    List<Account> findByUserIdAndActive(Long userId, Boolean active);

    boolean existsByAccountNumber(String accountNumber);

    @Query("SELECT a FROM Account a WHERE a.user.id = :userId AND a.accountType = :type")
    List<Account> findUserAccountsByType(@Param("userId") Long userId, 
                                         @Param("type") AccountType type);

    @Query("SELECT a FROM Account a WHERE a.balance > :minBalance")
    List<Account> findAccountsWithMinBalance(@Param("minBalance") BigDecimal minBalance);
}

