// src/main/java/com/abcbank/service/TransferService.java
package com.abcbank.service;

import com.abcbank.dto.request.TransferRequest;
import com.abcbank.dto.response.TransferResponse;
import com.abcbank.exception.AccountNotFoundException;
import com.abcbank.exception.InsufficientFundsException;
import com.abcbank.exception.InvalidAmountException;
import com.abcbank.model.Account;
import com.abcbank.model.Transaction;
import com.abcbank.model.TransactionType;
import com.abcbank.repository.AccountRepository;
import com.abcbank.repository.TransactionRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;

@Service
@Transactional
@RequiredArgsConstructor
@Slf4j
public class TransferService {

    private final AccountRepository accountRepository;
    private final TransactionRepository transactionRepository;

    public TransferResponse executeTransfer(TransferRequest request, String username) {
        log.info("Executing transfer: {} -> {}, amount: {}", 
            request.getFromAccount(), request.getToAccount(), request.getAmount());

        // Validate amount
        if (request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new InvalidAmountException("Transfer amount must be positive");
        }

        // Get accounts
        Account fromAccount = accountRepository
            .findByAccountNumber(request.getFromAccount())
            .orElseThrow(() -> new AccountNotFoundException("Source account not found"));

        Account toAccount = accountRepository
            .findByAccountNumber(request.getToAccount())
            .orElseThrow(() -> new AccountNotFoundException("Destination account not found"));

        // Verify ownership
        if (!fromAccount.getUser().getUsername().equals(username)) {
            throw new SecurityException("You don't own the source account");
        }

        // Check balance
        if (fromAccount.getBalance().compareTo(request.getAmount()) < 0) {
            throw new InsufficientFundsException("Insufficient balance in source account");
        }

        // Perform transfer
        fromAccount.setBalance(fromAccount.getBalance().subtract(request.getAmount()));
        toAccount.setBalance(toAccount.getBalance().add(request.getAmount()));

        // Generate reference number
        String referenceNumber = "TXN" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();

        // Create transaction records
        Transaction debitTxn = Transaction.builder()
            .account(fromAccount)
            .amount(request.getAmount().negate())
            .transactionType(TransactionType.TRANSFER_OUT)
            .description(request.getDescription() != null ? 
                request.getDescription() : "Transfer to " + request.getToAccount())
            .referenceNumber(referenceNumber)
            .balanceAfter(fromAccount.getBalance())
            .timestamp(LocalDateTime.now())
            .build();

        Transaction creditTxn = Transaction.builder()
            .account(toAccount)
            .amount(request.getAmount())
            .transactionType(TransactionType.TRANSFER_IN)
            .description("Transfer from " + request.getFromAccount())
            .referenceNumber(referenceNumber)
            .balanceAfter(toAccount.getBalance())
            .timestamp(LocalDateTime.now())
            .build();

        // Save everything
        accountRepository.saveAll(List.of(fromAccount, toAccount));
        transactionRepository.saveAll(List.of(debitTxn, creditTxn));

        log.info("Transfer completed successfully. Reference: {}", referenceNumber);

        return TransferResponse.builder()
            .success(true)
            .message("Transfer successful")
            .referenceNumber(referenceNumber)
            .build();
    }
}

