// src/main/java/com/abcbank/controller/TransferController.java
package com.abcbank.controller;

import com.abcbank.dto.request.TransferRequest;
import com.abcbank.dto.response.TransferResponse;
import com.abcbank.service.TransferService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.security.Principal;

@RestController
@RequestMapping("/api/transfers")
@RequiredArgsConstructor
@Slf4j
public class TransferController {

    private final TransferService transferService;

    @PostMapping
    public ResponseEntity<TransferResponse> executeTransfer(
            @Valid @RequestBody TransferRequest request,
            Principal principal) {

        log.info("Transfer request from user: {}", principal.getName());
        TransferResponse response = transferService.executeTransfer(request, principal.getName());
        return ResponseEntity.ok(response);
    }
}

