// src/main/java/com/abcbank/dto/request/TransferRequest.java
package com.abcbank.dto.request;

import jakarta.validation.constraints.*;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.math.BigDecimal;

@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class TransferRequest {

    @NotBlank(message = "Source account is required")
    @Pattern(regexp = "ACC\\d{4}", message = "Invalid account number format")
    private String fromAccount;

    @NotBlank(message = "Destination account is required")
    @Pattern(regexp = "ACC\\d{4}", message = "Invalid account number format")
    private String toAccount;

    @NotNull(message = "Amount is required")
    @DecimalMin(value = "0.01", message = "Amount must be at least 0.01")
    @DecimalMax(value = "1000000.00", message = "Amount cannot exceed 1,000,000.00")
    @Digits(integer = 10, fraction = 2, message = "Invalid amount format")
    private BigDecimal amount;

    @Size(max = 200, message = "Description cannot exceed 200 characters")
    private String description;
}

// src/main/java/com/abcbank/dto/response/TransferResponse.java
package com.abcbank.dto.response;

import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class TransferResponse {
    private Boolean success;
    private String message;
    private String referenceNumber;
}

