// src/main/java/com/abcbank/exception/GlobalExceptionHandler.java
package com.abcbank.exception;

import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;

@ControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    @ExceptionHandler(AccountNotFoundException.class)
    public ResponseEntity<ErrorResponse> handleAccountNotFound(AccountNotFoundException ex) {
        log.warn("Account not found: {}", ex.getMessage());
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.NOT_FOUND.value())
            .error("Not Found")
            .message(ex.getMessage())
            .build();
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(InsufficientFundsException.class)
    public ResponseEntity<ErrorResponse> handleInsufficientFunds(InsufficientFundsException ex) {
        log.warn("Insufficient funds: {}", ex.getMessage());
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.BAD_REQUEST.value())
            .error("Bad Request")
            .message(ex.getMessage())
            .build();
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ErrorResponse> handleValidationErrors(MethodArgumentNotValidException ex) {
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getAllErrors().forEach(error -> {
            String fieldName = ((FieldError) error).getField();
            String errorMessage = error.getDefaultMessage();
            errors.put(fieldName, errorMessage);
        });

        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.BAD_REQUEST.value())
            .error("Validation Failed")
            .message("Invalid input")
            .validationErrors(errors)
            .build();
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleGenericException(Exception ex) {
        log.error("Unexpected error", ex);
        ErrorResponse error = ErrorResponse.builder()
            .timestamp(LocalDateTime.now())
            .status(HttpStatus.INTERNAL_SERVER_ERROR.value())
            .error("Internal Server Error")
            .message("An unexpected error occurred")
            .build();
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }
}

testing_examples.unit_test_example:

// src/test/java/com/abcbank/service/TransferServiceTest.java
package com.abcbank.service;

import com.abcbank.dto.request.TransferRequest;
import com.abcbank.dto.response.TransferResponse;
import com.abcbank.exception.AccountNotFoundException;
import com.abcbank.exception.InsufficientFundsException;
import com.abcbank.model.Account;
import com.abcbank.model.AccountType;
import com.abcbank.model.User;
import com.abcbank.repository.AccountRepository;
import com.abcbank.repository.TransactionRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.math.BigDecimal;
import java.util.Optional;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class TransferServiceTest {

    @Mock
    private AccountRepository accountRepository;

    @Mock
    private TransactionRepository transactionRepository;

    @InjectMocks
    private TransferService transferService;

    private User user;
    private Account fromAccount;
    private Account toAccount;

    @BeforeEach
    void setUp() {
        user = User.builder()
            .id(1L)
            .username("john.doe")
            .build();

        fromAccount = Account.builder()
            .id(1L)
            .accountNumber("ACC1001")
            .user(user)
            .accountType(AccountType.SAVINGS)
            .balance(new BigDecimal("1000.00"))
            .active(true)
            .build();

        toAccount = Account.builder()
            .id(2L)
            .accountNumber("ACC2001")
            .accountType(AccountType.SAVINGS)
            .balance(new BigDecimal("500.00"))
            .active(true)
            .build();
    }

    @Test
    void executeTransfer_Success() {
        // Given
        TransferRequest request = TransferRequest.builder()
            .fromAccount("ACC1001")
            .toAccount("ACC2001")
            .amount(new BigDecimal("100.00"))
            .description("Test transfer")
            .build();

        when(accountRepository.findByAccountNumber("ACC1001"))
            .thenReturn(Optional.of(fromAccount));
        when(accountRepository.findByAccountNumber("ACC2001"))
            .thenReturn(Optional.of(toAccount));

        // When
        TransferResponse response = transferService.executeTransfer(request, "john.doe");

        // Then
        assertThat(response.getSuccess()).isTrue();
        assertThat(response.getMessage()).isEqualTo("Transfer successful");
        assertThat(response.getReferenceNumber()).isNotNull();

        assertThat(fromAccount.getBalance()).isEqualByComparingTo("900.00");
        assertThat(toAccount.getBalance()).isEqualByComparingTo("600.00");

        verify(accountRepository).saveAll(anyList());
        verify(transactionRepository).saveAll(anyList());
    }

    @Test
    void executeTransfer_InsufficientFunds_ThrowsException() {
        // Given
        TransferRequest request = TransferRequest.builder()
            .fromAccount("ACC1001")
            .toAccount("ACC2001")
            .amount(new BigDecimal("2000.00"))
            .build();

        when(accountRepository.findByAccountNumber("ACC1001"))
            .thenReturn(Optional.of(fromAccount));
        when(accountRepository.findByAccountNumber("ACC2001"))
            .thenReturn(Optional.of(toAccount));

        // When/Then
        assertThatThrownBy(() -> transferService.executeTransfer(request, "john.doe"))
            .isInstanceOf(InsufficientFundsException.class)
            .hasMessageContaining("Insufficient balance");

        verify(accountRepository, never()).saveAll(anyList());
    }

    @Test
    void executeTransfer_AccountNotFound_ThrowsException() {
        // Given
        TransferRequest request = TransferRequest.builder()
            .fromAccount("ACC9999")
            .toAccount("ACC2001")
            .amount(new BigDecimal("100.00"))
            .build();

        when(accountRepository.findByAccountNumber("ACC9999"))
            .thenReturn(Optional.empty());

        // When/Then
        assertThatThrownBy(() -> transferService.executeTransfer(request, "john.doe"))
            .isInstanceOf(AccountNotFoundException.class)
            .hasMessageContaining("Source account not found");
    }
}

