// src/test/java/com/abcbank/controller/TransferControllerIntegrationTest.java
package com.abcbank.controller;

import com.abcbank.dto.request.TransferRequest;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.security.test.context.support.WithMockUser;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class TransferControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Test
    @WithMockUser(username = "john.doe", roles = "USER")
    void executeTransfer_ValidRequest_ReturnsSuccess() throws Exception {
        TransferRequest request = TransferRequest.builder()
            .fromAccount("ACC1001")
            .toAccount("ACC2001")
            .amount(new BigDecimal("100.00"))
            .description("Test transfer")
            .build();

        mockMvc.perform(post("/api/transfers")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.success").value(true))
            .andExpect(jsonPath("$.message").value("Transfer successful"))
            .andExpect(jsonPath("$.referenceNumber").exists());
    }

    @Test
    @WithMockUser(username = "john.doe", roles = "USER")
    void executeTransfer_InvalidAmount_ReturnsBadRequest() throws Exception {
        TransferRequest request = TransferRequest.builder()
            .fromAccount("ACC1001")
            .toAccount("ACC2001")
            .amount(new BigDecimal("-100.00"))
            .build();

        mockMvc.perform(post("/api/transfers")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(request)))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.error").value("Validation Failed"));
    }
}
